-- FSI_DEMO_DB_V3.INSURANCE.POLICIES

CREATE OR REPLACE TABLE FSI_DEMO_DB_V3.INSURANCE.POLICIES (

    POLICY_ID VARCHAR(20) NOT NULL,
    POLICYHOLDER_ID VARCHAR(20),
    POLICY_TYPE VARCHAR(50),
    PRODUCT_NAME VARCHAR(100),
    EFFECTIVE_DATE DATE,
    EXPIRATION_DATE DATE,
    STATUS VARCHAR(20),
    PREMIUM_AMOUNT NUMBER(12,2),
    PREMIUM_FREQUENCY VARCHAR(20),
    COVERAGE_AMOUNT NUMBER(15,2),
    DEDUCTIBLE NUMBER(10,2),
    UNDERWRITING_CLASS VARCHAR(30),
    RISK_SCORE NUMBER(5,4),
    AGENTS_ID VARCHAR(20),
    CHANNEL VARCHAR(30),
    RENEWAL_COUNT NUMBER(3,0),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (POLICY_ID)

);






